  } else {
    const labelUrgency = t('Urgency', 'Khẩn cấp');
    const labelMainBlocker = t('Main blocker', 'Blocker chính');
    const labelQuickWin = t('Quick win', 'Quick win');
    const labelDecisionToday = t('Decision today', 'Quyết định hôm nay');

    if (asText(render.urgencyLine)) narrativeLines.push('• ' + labelUrgency + ': ' + render.urgencyLine);
    if (asText(render.mainBlockerLine)) narrativeLines.push('• ' + labelMainBlocker + ': ' + render.mainBlockerLine);
    if (asText(render.quickWinLine)) narrativeLines.push('• ' + labelQuickWin + ': ' + render.quickWinLine);
    if (asText(render.decisionTodayLine)) narrativeLines.push('• ' + labelDecisionToday + ': ' + render.decisionTodayLine);

    const narrativeBody = narrativeLines.join('\n');
    const narrativeWithMentionTail = asText(render.mentionTail)
      ? narrativeBody + '\n' + asText(render.mentionTail)
      : narrativeBody;
    const narrativeText = renderJiraLinks(narrativeWithMentionTail);

    const cardPayload = {
      cardsV2: [
        {
          cardId: 'sprint-monitor-unified-digest',
