              {
                widgets: [
                  {
                    decoratedText: {
                      text: '<b>' + t('Sprint status', 'Trạng thái sprint') + ': ' + asText(render.sprintStatus, t('at risk', 'at risk')) + '</b><br>' + t('Days left', 'Số ngày còn lại') + ': ' + String(render.daysLeft ?? 0),
                      wrapText: true,
